                try {
                    value = Integer.parseInt(raw.trim());
                } catch (NumberFormatException e) {
                    throw new ContainerException(def.key + " must be a valid integer, got '" + raw + "'", e);
                }
                if (value < 0) {
                    throw new ContainerException(def.key + " must be non-negative, got " + value);
                }
                yield value;
