        try {
            DockerClientFactory.client().removeImageCmd(image).withForce(true).exec();

            ContainerSpec spec =
                    ContainerSpec.builder(image).command("sleep", "30").build();
            container = Container.create(spec);

            assertThat(container.isRunning()).isTrue();
        } finally {
