                String trimmed = raw.trim().toLowerCase(Locale.ROOT);
                if (!trimmed.equals("true") && !trimmed.equals("false")) {
                    throw new ContainerException(def.key + " must be 'true' or 'false', got '" + raw + "'");
                }
                yield Boolean.parseBoolean(trimmed);
